VALUES ('82a1758a-bbc7-4a29-a4d3-f1b96517fe0d', 'Which expression is equivalent to $(4x + 8)(4x - 8)$?', NULL, NULL, '[{"id":"A","text":"$4x^2 - 8$","is_correct":false,"explanation":"Incorrect square of the first term."},{"id":"B","text":"$16x^2 - 64$","is_correct":true,"explanation":"Difference of squares: $(4x)^2 - (8)^2 = 16x^2 - 64$."},{"id":"C","text":"$8x - 16$","is_correct":false,"explanation":"This expands to a linear expression, not the quadratic."},{"id":"D","text":"$12x^2$","is_correct":false,"explanation":"Does not follow the product pattern."}]'::jsonb, 'B', 'Use difference of squares: $(4x + 8)(4x - 8) = 16x^2 - 64$.', NULL, 'Advanced Math', 'Equivalent expressions', 'math', 'advanced', 'EQS', 'EQS', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
