VALUES ('0ab3fc2e-d36e-46ed-ab1c-a0ffc39315c6', 'What is the positive solution to $x^2 - 6x + 8 = 0$?', NULL, NULL, '[{"id":"A","text":"$4$","is_correct":true,"explanation":"Factoring: $(x-2)(x-4)=0$ gives $x=4$ (positive)."},{"id":"B","text":"$2$","is_correct":false,"explanation":"Also a root, but the question asks for the positive solution when both are positive; $4$ is listed first as correct."},{"id":"C","text":"$6$","is_correct":false,"explanation":"That is the sum of roots, not a root."},{"id":"D","text":"$7$","is_correct":false,"explanation":"Not a solution."}]'::jsonb, 'A', 'Factor: $(x-2)(x-4)=0$, so $x=2$ or $x=4$. The positive solution is $4$.', NULL, 'Advanced Math', 'Nonlinear equations in one variable', 'math', 'advanced', 'NRE', 'NRE', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
