VALUES ('de545e2e-8fa7-49c5-a84d-1cc0ff0c31a4', 'For $f(x) = 1(x - 6)^2 + 8$, what is the value of $f(8)$?', NULL, NULL, '[{"id":"A","text":"$8$","is_correct":false,"explanation":"That is $f(6)$, the vertex value."},{"id":"B","text":"$9$","is_correct":false,"explanation":"Adds coefficient and constant incorrectly."},{"id":"C","text":"$12$","is_correct":true,"explanation":"$f(8) = 1(8-6)^2 + 8 = 1(4)+8 = 12$."},{"id":"D","text":"$13$","is_correct":false,"explanation":"Too large by $${a}$."}]'::jsonb, 'C', 'Substitute $x=8$: $f(8) = 1(2)^2+8 = 12$.', NULL, 'Advanced Math', 'Nonlinear functions', 'math', 'advanced', 'NRM', 'NRM', 'hard', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
