VALUES ('61e37ffa-8a2a-4f10-a17a-485189a51242', 'Which choice best evaluates the blogger''s claim?', 'A blogger writes, "Everyone in the city opposes the new bike lane," after surveying 110 people at one weekend farmers market.', NULL, '[{"id":"A","text":"The claim is valid because 50 people is a large sample","is_correct":false,"explanation":"Sample size alone does not fix selection bias."},{"id":"B","text":"The claim is valid because farmers markets represent all residents","is_correct":false,"explanation":"One location on one weekend is not citywide representation."},{"id":"C","text":"The claim is valid because weekend opinions never change","is_correct":false,"explanation":"No evidence supports this absolutist statement."},{"id":"D","text":"The claim is overstated because the sample is not representative of the whole city","is_correct":true,"explanation":"Convenience samples cannot support ''everyone'' claims."}]'::jsonb, 'D', 'Generalizing from a single venue to ''everyone in the city'' overreaches the evidence.', NULL, 'Problem-Solving and Data Analysis', 'Evaluating statistical claims', 'math', 'psda', 'EVA', 'EVA', 'medium', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
