VALUES ('70b31b0f-d75c-42fb-9471-0c550d929b37', 'What is the circumference of the circle? (Use $\pi \approx 3.14$.)', 'A circle has center $O$ and radius 7.', NULL, '[{"id":"A","text":"$153.86$","is_correct":false,"explanation":"That is an area expression $\\pi r^2$, not circumference."},{"id":"B","text":"$43.96$","is_correct":true,"explanation":"Circumference $C = 2\\pi r \\approx 2(3.14)(7) = 43.96$."},{"id":"C","text":"$14.00$","is_correct":false,"explanation":"That is the diameter, not circumference."},{"id":"D","text":"$21.98$","is_correct":false,"explanation":"That is $\\pi r$, not $2\\pi r$."}]'::jsonb, 'B', '$C = 2\pi r \approx 2(3.14)(7) = 43.96$.', NULL, 'Geometry and Trigonometry', 'Circles', 'math', 'geometry', 'CIR', 'CIR', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
